import sys

def nearest_smaller_to_left(A):
    n = len(A)
    L = [-1] * n
    stack = []
    for i in range(n):
        while stack and A[stack[-1]] >= A[i]:
            stack.pop()
        if stack:
            L[i] = A[stack[-1]]
        stack.append(i)
    return sum(L)

def main():
    n = int(input())
    A = list(map(int, input().split()))
    result = nearest_smaller_to_left(A)
    print(result)

if __name__ == "__main__":
    main()
